// ❌ BAD - Fire and forget with no confirmation, message can be lost on crash
await sender.SendMessageAsync(new ServiceBusMessage(orderJson));
ProcessOrder(order); // crashes here - message sent but order never processed

// ✅ GOOD - PeekLock: process first, complete only on success
ServiceBusReceivedMessage msg = await receiver.ReceiveMessageAsync();
try {
    await orderService.ProcessAsync(msg.Body.ToString());
    await receiver.CompleteMessageAsync(msg); // remove from queue only after success
} catch {
    await receiver.AbandonMessageAsync(msg); // requeue for retry
}

