// ❌ BAD - Silently abandon invalid messages, they retry forever and clog delivery count
ServiceBusReceivedMessage msg = await receiver.ReceiveMessageAsync();
if (!IsValidOrder(msg.Body.ToString())) {
    await receiver.AbandonMessageAsync(msg); // will hit max retries, wastes 10 attempts
}

// ✅ GOOD - Explicitly dead-letter with a reason for diagnosis
if (!IsValidOrder(msg.Body.ToString())) {
    await receiver.DeadLetterMessageAsync(
        msg,
        deadLetterReason: "InvalidOrderSchema",
        deadLetterErrorDescription: "Missing required field: CustomerId"
    );
}

// ❌ BAD - ReceiveAndDelete for payment processing - crash loses the payment record
var receiver = client.CreateReceiver("payment-queue",
    new ServiceBusReceiverOptions { ReceiveMode = ServiceBusReceiveMode.ReceiveAndDelete });
var msg = await receiver.ReceiveMessageAsync();
await _paymentGateway.ChargeAsync(msg.Body); // crash here = message gone, charge unrecorded

// ✅ GOOD - PeekLock for payment processing - crash causes safe redelivery
var receiver = client.CreateReceiver("payment-queue"); // PeekLock is default
var msg = await receiver.ReceiveMessageAsync();
try {
    await _paymentGateway.ChargeAsync(msg.Body);
    await receiver.CompleteMessageAsync(msg);
} catch {
    await receiver.AbandonMessageAsync(msg); // requeue for retry
}

// ❌ BAD - New GUID every send, duplicate detection cannot help on retry
var msg = new ServiceBusMessage(JsonSerializer.Serialize(paymentRequest));
msg.MessageId = Guid.NewGuid().ToString(); // different ID each attempt = duplicates get through
await sender.SendMessageAsync(msg);

// ✅ GOOD - Deterministic MessageId from the business key
var msg = new ServiceBusMessage(JsonSerializer.Serialize(paymentRequest));
msg.MessageId = $"payment-{paymentRequest.PaymentId}"; // same ID on retry = deduplication works
await sender.SendMessageAsync(msg);

// ❌ BAD - No sessions, concurrent consumers process account transactions out of order
await sender.SendMessageAsync(new ServiceBusMessage("Deposit 100"));
await sender.SendMessageAsync(new ServiceBusMessage("Withdraw 150")); // may process before deposit!

// ✅ GOOD - Sessions ensure deposit always processes before withdraw for same account
var depositMsg = new ServiceBusMessage("Deposit 100") { SessionId = "account-99201" };
var withdrawMsg = new ServiceBusMessage("Withdraw 150") { SessionId = "account-99201" };
await sender.SendMessageAsync(depositMsg);
await sender.SendMessageAsync(withdrawMsg);
// Consumer receives session account-99201 and processes in FIFO order

// ❌ BAD - Competing consumers with no sessions, order steps process out of sequence
var step1 = new ServiceBusMessage("CreateOrder");
var step2 = new ServiceBusMessage("ReserveInventory");
// Consumer A gets step2, Consumer B gets step1 - inventory reserved before order exists!

// ✅ GOOD - Session-based ordering per order ID
var orderId = "ORD-88412";
var step1 = new ServiceBusMessage("CreateOrder") { SessionId = orderId };
var step2 = new ServiceBusMessage("ReserveInventory") { SessionId = orderId };
var step3 = new ServiceBusMessage("SendConfirmation") { SessionId = orderId };
// One consumer processes ORD-88412 in FIFO order: create, reserve, confirm

