// ❌ BAD - Using Event Grid alone for a payment command, wrong tool for durability
// If the payment Function is down beyond Event Grid's 24h retry window, payment is lost

// ✅ GOOD - Event Grid for notification, Service Bus for the durable payment command
// Step 1: React to checkout completed event via Event Grid
[Function("OnCheckoutCompleted")]
public async Task Run([EventGridTrigger] CloudEvent evt) {
    var order = evt.Data.ToObjectFromJson<OrderSummary>();
    // Step 2: Drop payment command onto Service Bus for guaranteed processing
    await _serviceBusSender.SendMessageAsync(
        new ServiceBusMessage(JsonSerializer.Serialize(order))
        { SessionId = order.OrderId }); // sessions for ordering
}

// ❌ BAD - Returning 200 without handling the validation handshake
[HttpPost("/webhook")]
public IActionResult Receive([FromBody] JsonElement body) {
    return Ok(); // accepts any payload, validation never completes, no real events delivered
}

// ✅ GOOD - Handle validation handshake then process real events
[HttpPost("/webhook")]
public IActionResult Receive([FromBody] EventGridEvent[] events) {
    foreach (var evt in events) {
        if (evt.EventType == "Microsoft.EventGrid.SubscriptionValidationEvent") {
            var data = evt.Data.ToObjectFromJson<SubscriptionValidationData>();
            return Ok(new { validationResponse = data.ValidationCode }); // echo code back
        }
        _processor.ProcessAsync(evt); // handle real events
    }
    return Ok();
}

